tuple<int, vector<vector<int>>, vector<vector<int>>> scc_shrink(int n, const vector<vector<int>>& g) {
	auto dfn = vector<int>(n + 1); // dfs 时间戳
	auto low = vector<int>(n + 1); // i 点能回溯到的最顶端祖先的 dfn
	auto ins = vector<int>(n + 1); // 是否在栈内
	auto bel = vector<int>(n + 1); // i 点属于第几个强连通分量
	auto st = stack<int>();        // 正在处理的栈
	int time = 0;                  // 时间戳
	int scc = 0;                   // 强连通分量个数，同时也是新图节点个数(单个节点也是个 scc)

	auto tarjan = [&](auto tarjan, int now)->void {
		dfn[now] = low[now] = ++time;
		st.push(now);
		ins[now] = 1;
		for (const int& to : g[now]) {
			if (!dfn[to]) { // 未遍历到的节点
				tarjan(tarjan, to);
				low[now] = min(low[now], low[to]);
			}
			else if (ins[to]) { // 环
				low[now] = min(low[now], dfn[to]);
			}
		}
		// 弹栈缩点
		if (low[now] == dfn[now]) {
			scc++;
			while (1) {
				int cur = st.top();
				st.pop();
				ins[cur] = 0;
				bel[cur] = scc;
				if (now == cur)break;
			}
		}
		};
	for (int i = 1; i <= n; i++) if (!dfn[i]) tarjan(tarjan, i);

	// 构建新有向图
	auto ng = vector<vector<int>>(n + 1);
	auto ps = vector<vector<int>>(scc + 1);

	for (int now = 1; now <= n; now++) {
		ps[bel[now]].pb(now);
		for (const int& to : g[now])
			if (bel[to] == bel[now])ng[now].pb(to);
	}

	return make_tuple(scc, ng, ps);
}
void solve(int CASE)
{
	int n, m; cin >> n >> m;
	var g = vector<vector<int>>(n + 1);
	fa(i, 1, m) {
		int u, v; cin >> u >> v;
		g[u].pb(v);
	}

	// 找出所有的 SCC
	var[scc, ng, ps] = scc_shrink(n, g); 
	var col = vector<int>(n + 1, -1);
	col[0] = 1;
	var dfs = [&](var dfs, int now, int fa)->bool {
		col[now] = col[fa] ^ 1;
		for (int to : ng[now]) {
			if (col[to] != -1) {
				if (col[now] == col[to])return 1;
			}
			else {
				if (dfs(dfs, to, now))return 1;
			}
		}
		return 0;
		};

	// 在每个 SCC 内用染色法判奇环
	var ans = vector<int>(n + 1, -1);
	fa(i, 1, scc) if (ps[i].size()) {
		int res = 0;
		if (dfs(dfs, ps[i][0], 0))res = 1;
		for (int x : ps[i])ans[x] = res;
	}

	fa(i, 1, n)cout << ans[i];
	cout << endl;
	return;
}
